class Solution:

def solve(self, nums: list[int]) -> bool:
	pivot = nums[0]
	nums.remove(pivot)
	while nums:
		if len(nums) <= 1:
			break
		p = nums[len(nums) // 2]
		l = [x for x in nums if x <= p]
		r = [x for x in nums if x > p]
		nums = l + [pivot] + r
	return nums
print(Solution().solve([4, 2, 6, 1, 3]))
